BatchClient client = new BatchClient(Guid.Parse("73f411fe-4f43-4b4b-9cbd-6828d8f4cf9a"), credential);

using RequestContent content = RequestContent.Create(new
{
    requests = new object[]
    {
        new
        {
            id = "<id>",
            method = "GET",
            url = "<url>",
        }
    },
});
Operation<AsyncPageable<BinaryData>> operation = await client.InvokeAtSubscriptionScopeAsync(WaitUntil.Completed, content);
AsyncPageable<BinaryData> responseData = operation.Value;
await foreach (BinaryData item in operation.Value)
